const express = require('express');
const rateLimit = require('express-rate-limit');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100
});

app.use(limiter);

const users = [
  {
    id: 1,
    username: 'admin',
    password: 'password',
    role: 'ADMIN'
  },
  {
    id: 2,
    username: 'user',
    password: 'password',
    role: 'USER'
  }
];

const authenticate = (req, res, next) => {
  const token = req.header('Authorization');
  if (!token) return res.status(401).send({
    error: 'Unauthorized'
  });

  jwt.verify(token, 'secretKey', (err, user) => {
    if (err) return res.status(401).send({
      error: 'Invalid token'
    });

    req.user = user;
    next();
  });
};

const checkRole = (role) => {
  return (req, res, next) => {
    if (req.user.role !== role) return res.status(403).send({
      error: 'Forbidden'
    });

    next();
  };
};

app.post('/api/auth/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find((u) => u.username === username && u.password === password);
  if (!user) return res.status(401).send({
    error: 'Invalid credentials'
  });

  const token = jwt.sign({ id: user.id, role: user.role }, 'secretKey');
  res.send({
    token
  });
});

app.get('/api/admin/books', authenticate, checkRole('ADMIN'), (
  req, res
) => {
  res.send({
    books: users.map((user) => ({ id: user.id, username: user.username }))
  });
});

app.get('/api/books/:id', authenticate, (
  req, res
) => {
  const id = parseInt(req.params.id);
  const user = users.find((u) => u.id === id);
  if (!user) return res.status(404).send({
    error: 'Book not found'
  });

  res.send({
    book: user
  });
});

app.post('/api/books', authenticate, (
  req, res
) => {
  const { title, author } = req.body;
  const user = users.find((u) => u.id === req.user.id);
  const book = {
    id: users.length + 1,
    title,
    author,
    user:{
        id:user.id,
        username:user.username
    }
  };
  users.push(book);
  res.send({
    book
  });
});

app.patch('/api/books/:id', authenticate, (
  req, res
) => {
  const id = parseInt(req.params.id);
  const user = users.find((u) => u.id === id);
  if (!user) return res.status(404).send({
    error: 'Book not found'
  });

  const { title, author } = req.body;
  user.title = title;
  user.author = author;
  res.send({
    book: user
  });
});

app.delete('/api/books/:id', authenticate, (
  req, res
) => {
  const id = parseInt(req.params.id);
  const index = users.findIndex((u) => u.id === id);
  if (index === -1) return res.status(404).send({
    error: 'Book not found'
  });

  users.splice(index, 1);
  res.send({
    message: 'Book deleted'
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log('Server running on port ' + PORT));
